<template>
  <div class="box">
    <canvas ref="canvas"></canvas>
    <div class="right-box">
      <div class="notice">
        <p><span>INVOICE #:</span>取随机数100~999</p>
        <p><span>INVOICE DATE:</span>会显示当天日期</p>
        <p><span>DUT DATE:</span>会显示一年后的日期</p>
      </div>
      <div class="content-box">
        <label>公司名字: </label>
        <input type="text" v-model="name">
      </div>
      <div class="content-box">
        <label>邮箱账号: </label>
        <input type="text" v-model="email">
      </div>
      <div class="content-box">
        <label>收据金额: </label>
        <input type="number" v-model="money">
        <label style="position: absolute;margin-left: 10px;color:red;">*只可以填纯数字</label>
      </div>
      <div class="content-box">
        <button @click="reloadPage">刷新网页</button>
        <button @click="drawMoreText">生成</button>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      name: '',
      email: '',
      money: null,
      imageLoaded: false,
      textColor: '#000000',
      fapiao: require('@/assets/FAPIAO.png'),
    };
  },
  mounted() {
    this.loadImage();
  },
  methods: {
    reloadPage() {
      location.reload()
    },
    loadImage() {
      const img = new Image();
      img.onload = () => {
        this.setupCanvas(img);
        this.adjustImage();
        this.drawText('2312/2024', 625, 254, '500 17px Agency FB', true, true)
      };
      img.src = this.fapiao;
    },
    setupCanvas(img) {
      const canvas = this.$refs.canvas;
      const ctx = canvas.getContext('2d');
      canvas.width = img.width;
      canvas.height = img.height;
      ctx.drawImage(img, 0, 0);
      this.imageLoaded = true;
    },
    adjustImage() {
      const canvas = this.$refs.canvas;
      const ctx = canvas.getContext('2d');
      let imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      imageData = this.applyContrast(imageData, 30); // 30的对比度提升
      ctx.putImageData(imageData, 0, 0);
      this.calculateTextColor(imageData);
    },
    calculateTextColor(imageData) {
      let r = 0, g = 0, b = 0, total = 0;
      const data = imageData.data;
      for (let i = 0; i < data.length; i += 4) {
        r += data[i];
        g += data[i + 1];
        b += data[i + 2];
        total++;
      }
      r /= total;
      g /= total;
      b /= total;
      const brightness = Math.sqrt(0.299 * r * r + 0.587 * g * g + 0.114 * b * b);
      this.textColor = brightness > 128 ? '#000000' : '#FFFFFF';
    },
    applyContrast(data, contrast) {
      const factor = (259 * (contrast + 255)) / (255 * (259 - contrast));
      for (let i = 0; i < data.data.length; i += 4) {
        data.data[i] = factor * (data.data[i] - 128) + 128;
        data.data[i + 1] = factor * (data.data[i + 1] - 128) + 128;
        data.data[i + 2] = factor * (data.data[i + 2] - 128) + 128;
      }
      return data;
    },
    drawText(temp, x, y, font, tt, fromRight = false) {
      if (!this.imageLoaded) return;
      const canvas = this.$refs.canvas;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(canvas, 0, 0);
      ctx.font = font;
      ctx.fillStyle = "#030030";
      ctx.textAlign = fromRight ? 'right' : 'left';



      if (tt == 1) {
        ctx.fillText(temp, x, y);
      } else if (/[a-zA-Z]/.test(this.name)) {
        // 英文名公司字间距
        let letterSpacing = 0;
        let startX = x;
        let startY = y;

        for (let i = 0; i < temp.length; i++) {
          const char = temp[i];
          ctx.fillText(char, startX, startY);
          const metrics = ctx.measureText(char);
          startX += metrics.width + letterSpacing;
        }
      } else {
        let letterSpacing = 0;
        let startX = x;
        let startY = y;

        for (let i = 0; i < temp.length; i++) {
          const char = temp[i];
          ctx.fillText(char, startX, startY);
          const metrics = ctx.measureText(char);
          startX += metrics.width + letterSpacing;
        }
      }
    },
    getTodayDate(temp) {
      let date = new Date();
      date.setDate(date.getDate() - temp);
      let day = date.getDate().toString().padStart(2, '0');
      let month = (date.getMonth() + 1).toString().padStart(2, '0');
      let year = date.getFullYear();
      return `${day}/${month}/${year}`;
    },
    getRandomNumber() {
      let random = Math.floor(Math.random() * (1000 - 100) + 100)
      return random;
    },
    drawMoreText() {
      // ======= 邮箱 =======
      this.drawText(this.email, 256, 263, '16px Agency FB', true)
      this.drawText(this.email, 256, 263, '16px Agency FB', true)
      // ======= 日期 =======
      // INVOICE #
      this.drawText("US-" + this.getRandomNumber(), 625, 210, '500 17px Agency FB', true, true)
      // INVOICE DATE
      this.drawText(this.getTodayDate(0), 625, 232, '500 17px Agency FB', true, true)
      // P.O.#
      // this.drawText('2312/2024', 625, 254, '500 17px Agency FB', true, true)
      // DUE DATE
      this.drawText(this.getTodayDate(1), 625, 276, '500 17px Agency FB', true, true)
      // ======= 金额 =======
      // Unit Price
      this.drawText(this.money, 400, 377, '300 20px Agency FB', true)
      this.drawText(this.money, 400, 377, '300 20px Agency FB', true)
      // Amount
      this.drawText(this.money, 590, 377, '20px Agency FB', true)
      this.drawText(this.money, 590, 377, '20px Agency FB', true)
      // Tax
      this.drawText((this.money * 0.0625 + this.money).toFixed(1), 590, 414, '20px Agency FB', true)
      this.drawText((this.money * 0.0625 + this.money).toFixed(1), 590, 414, '20px Agency FB', true)
      // Total
      this.drawText("¥ " + (this.money * 0.0625 + this.money).toFixed(1), 575, 450, '900 20px Agency FB', true)
      // ======= 公司名称 =======
      if (!/[a-zA-Z]/.test(this.name)) {
        // Bill to
        this.drawText(this.name, 253, 145, '16px STZhongsong', false)
        // company
        if (this.name.length < 10) {
          this.drawText(this.name, 50, 377, '18px STZhongsong', false)
        } else {
          this.drawText(this.name.slice(0, 8), 50, 377, '18px STZhongsong', false)
          this.drawText(this.name.slice(8), 50, 399, '18px STZhongsong', false)
        }

      } else {
        // Bill to
        this.drawText(this.name, 253, 145, '16px Agency FB', false)
        // company
        let arr = this.name.split(" ")
        let firstText = arr[0] + " " + arr[1]
        this.drawText(firstText, 50, 377, '18px Agency FB', false)
        this.drawText(firstText, 50, 377, '18px Agency FB', false)

        let secondText = ""
        for (let i = 2; i < arr.length; i++) {
          secondText = secondText + arr[i] + " "
          console.log(secondText)
        }
        this.drawText(secondText, 50, 399, '18px Agency FB', false)
        this.drawText(secondText, 50, 399, '18px Agency FB', false)
      }
    }
  }
};
</script>

